use aiken/collection/list
use cardano/transaction.{OutputReference, Transaction}

validator owner_signed {
  spend(
    datum: Option<ByteArray>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(required_signer) ->
        list.has(self.extra_signatories, required_signer)
    }
  }
}

use cardano/transaction.{Transaction, OutputReference, InlineDatum}
use cardano/address.{Address}
use cardano/assets
use aiken/collection/list

validator ada_payment {
  spend(
    datum: Option<Int>,
    redeemer: Address,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(min_lovelace) = datum
    let target_address = redeemer
    list.any(
      self.outputs,
      fn(output) {
        output.address == target_address && assets.lovelace_of(output.value) >= min_lovelace
      },
    )
  }
}

