pub type EscrowDatum {
  beneficiary: ByteArray,
  amount: Int,
}

validator escrow_validator {
  spend(
    _datum: Option<EscrowDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    let outputs = self.outputs
    expect Some(output) =
      list.find(
        outputs,
        fn(o) {
          when o.datum is {
            InlineDatum(_) -> True
            _ -> False
          }
        },
      )
    expect InlineDatum(raw) = output.datum
    expect escrow: EscrowDatum = raw
    escrow.amount > 0 && escrow.beneficiary != ""
  }
}

