use cardano/transaction.{Transaction, OutputReference, InlineDatum}
use aiken/collection/list

pub type SpendDatum {
  min_price: Int,
}

pub type SpendRedeemer {
  oracle_ref: OutputReference,
}

validator oracle_spend {
  spend(
    datum: Option<SpendDatum>,
    redeemer: SpendRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let oracle_input =
      list.find(
        self.reference_inputs,
        fn(input) { input.output_reference == redeemer.oracle_ref },
      )
    expect Some(ref_input) = oracle_input
    expect InlineDatum(raw_datum) = ref_input.output.datum
    expect oracle_price: Int = raw_datum
    oracle_price >= d.min_price
  }
}

use cardano/transaction.{Transaction, OutputReference, InlineDatum, Input}
use aiken/collection/list

pub type OracleDatum {
  price: Int
}

pub type SpendDatum {
  oracle_ref: OutputReference,
  owner: ByteArray,
}

pub type SpendRedeemer {
  min_price: Int
}

validator oracle_spend {
  spend(
    datum: Option<SpendDatum>,
    redeemer: SpendRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let oracle_input: Input =
      self.reference_inputs
        |> list.find(fn(i) { i.output_reference == d.oracle_ref })
        |> fn(opt) {
             expect Some(i) = opt
             i
           }

    expect InlineDatum(raw) = oracle_input.output.datum
    expect oracle_datum: OracleDatum = raw

    let price_ok = oracle_datum.price >= redeemer.min_price
    let signed = list.has(self.extra_signatories, d.owner)

    price_ok && signed
  }
}

