use aiken/collection/list
use cardano/address.{Address, VerificationKey}
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}

pub type PaymentDatum {
  recipient: ByteArray,
  min_lovelace: Int,
}

validator ada_payment {
  spend(
    datum: Option<PaymentDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) ->
        list.any(
          self.outputs,
          fn(output) {
            let paid_enough = assets.lovelace_of(output.value) >= d.min_lovelace
            let goes_to_recipient =
              when output.address.payment_credential is {
                VerificationKey(hash) -> hash == d.recipient
                _ -> False
              }
            paid_enough && goes_to_recipient
          },
        )
    }
  }
}

