pub type WindowDatum {
  open_time: Int,
  close_time: Int,
}

validator time_locked {
  spend(
    datum: Option<WindowDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let after_open =
          interval.is_entirely_after(self.validity_range, d.open_time)
        let before_close =
          interval.is_entirely_before(self.validity_range, d.close_time)
        after_open && before_close
      }
    }
  }
}

