pub type EscrowDatum {
  beneficiary: ByteArray,
  amount: Int,
}

validator escrow {
  spend(
    datum: Option<EscrowDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let valid_amount = d.amount > 0
