use cardano/transaction.{InlineDatum, OutputReference, Transaction}

pub type PaymentDatum {
  recipient: ByteArray,
  min_lovelace: Int,
}

validator ada_payment {
  spend(
    datum: Option<PaymentDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) ->
        list.any(
          self.outputs,
          fn(output) {
            let pays_enough = assets.lovelace_of(output.value) >= d.min_lovelace
            let to_recipient =
              when output.address.payment_credential is {
                VerificationKey(pkh) -> pkh == d.recipient
                _ -> False
              }
            pays_enough && to_recipient
          },
        )
    }
  }
}

