  unlock_after: Int,
}

validator time_locked_vault {
  spend(
    datum: Option<VaultDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) ->
        interval.is_entirely_after(self.validity_range, d.unlock_after)
    }
  }
}

