use aiken/collection/list
use cardano/assets
use cardano/transaction.{Transaction, OutputReference}

pub type NftDatum {
  policy_id: ByteArray,
  asset_name: ByteArray,
}

validator nft_gate {
  spend(
    datum: Option<NftDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let has_nft =
          list.any(
            self.inputs,
            fn(input) {
              assets.quantity_of(input.output.value, d.policy_id, d.asset_name) > 0
            },
          )
        has_nft
      }
    }
  }
}

