use aiken/collection/list
use cardano/assets
use cardano/transaction.{Input, OutputReference, Transaction}

pub type NFTDatum {
  policy_id: ByteArray,
  asset_name: ByteArray,
}

validator nft_gate {
  spend(
    datum: Option<NFTDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(nft_datum) = datum
    let total_nft_quantity =
      list.foldl(
        self.inputs,
        0,
        fn(input: Input, acc: Int) {
          acc + assets.quantity_of(
            input.output.value,
            nft_datum.policy_id,
            nft_datum.asset_name,
          )
        },
      )
    total_nft_quantity > 0
  }
}

