pub type EscrowDatum {
  owner: ByteArray,
  amount: Int,
}

validator escrow {
  spend(
    datum: Option<EscrowDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let signed = list.has(self.extra_signatories, d.owner)
    let valid_amount = d.amount > 0
    signed && valid_amount
  }
}

