use aiken/collection/list
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}

pub type VaultDatum {
  owner: ByteArray,
  min_ada: Int,
}

validator secure_vault {
  spend(
    datum: Option<VaultDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let signed = list.has(self.extra_signatories, d.owner)
    let has_sufficient_output =
      list.any(
        self.outputs,
        fn(output) { assets.lovelace_of(output.value) >= d.min_ada },
      )
    signed && has_sufficient_output
  }
}

