use cardano/assets
use cardano/transaction.{Transaction}

validator burn_only {
  mint(redeemer: ByteArray, policy_id: ByteArray, self: Transaction) {
    let qty = assets.quantity_of(self.mint, policy_id, redeemer)
    qty < 0
  }
}

use aiken/collection/list
use cardano/address.{Credential}
use cardano/transaction.{Transaction}

validator staking_owner(owner: ByteArray) {
  withdraw(_redeemer: Data, _account: Credential, self: Transaction) {
    list.has(self.extra_signatories, owner)
  }
}

use aiken/collection/pairs
use cardano/address.{Credential}
use cardano/transaction.{Transaction}

validator min_rewards(min_amount: Int) {
  withdraw(_redeemer: Data, account: Credential, self: Transaction) {
    when pairs.get_first(self.withdrawals, account) is {
      None -> False
      Some(amount) -> amount >= min_amount
    }
  }
}

use aiken/interval
use cardano/address.{Credential}
use cardano/transaction.{Transaction}

validator timed_staking(deadline: Int) {
  withdraw(_redeemer: Data, _account: Credential, self: Transaction) {
    interval.is_entirely_after(self.validity_range, deadline)
  }
}

use aiken/collection/list
use cardano/address.{Credential}
use cardano/transaction.{Transaction}

pub type StakeRedeemer {
  required_signers: List<ByteArray>,
  threshold: Int,
}

validator multisig_staking {
  withdraw(redeemer: StakeRedeemer, _account: Credential, self: Transaction) {
    let present = list.count(
      self.extra_signatories,
      fn(sig) { list.has(redeemer.required_signers, sig) },
    )
    present >= redeemer.threshold
  }
}

use aiken/collection/list
use cardano/address.{Credential}
use cardano/assets
use cardano/transaction.{Transaction}

validator nft_gated_staking(policy_id: ByteArray, asset_name: ByteArray) {
  withdraw(_redeemer: Data, _account: Credential, self: Transaction) {
    list.any(
      self.inputs,
      fn(input) {
        assets.quantity_of(input.output.value, policy_id, asset_name) > 0
      },
    )
  }
}

use aiken/collection/list
use cardano/address.{Credential}
use cardano/transaction.{Transaction}

validator two_key_staking(hot_key: ByteArray, cold_key: ByteArray) {
  withdraw(_redeemer: Data, _account: Credential, self: Transaction) {
    list.has(self.extra_signatories, hot_key)
      && list.has(self.extra_signatories, cold_key)
  }
}

use aiken/collection/list
use cardano/address.{Credential, VerificationKey}
use cardano/assets
use cardano/transaction.{Transaction}

validator fee_split_staking(fee_collector: ByteArray, fee_amount: Int) {
  withdraw(_redeemer: Data, _account: Credential, self: Transaction) {
    list.any(
      self.outputs,
      fn(output) {
        output.address.payment_credential == VerificationKey(fee_collector)
          && assets.lovelace_of(output.value) >= fee_amount
      },
    )
  }
}

use aiken/collection/list
use cardano/address.{Credential}
use cardano/transaction.{Transaction}

validator paused_staking(owner: ByteArray, paused: Bool) {
  withdraw(_redeemer: Data, _account: Credential, self: Transaction) {
    !paused && list.has(self.extra_signatories, owner)
  }
}

use aiken/collection/pairs
use cardano/address.{Credential}
use cardano/transaction.{Transaction}

validator rewards_accumulator {
  withdraw(_redeemer: Data, account: Credential, self: Transaction) {
    when pairs.get_first(self.withdrawals, account) is {
      None -> False
      Some(amount) -> amount >= 1000000
    }
  }
}

use aiken/collection/list
use aiken/interval
use cardano/address.{Credential}
use cardano/transaction.{Transaction}

validator vesting_staking(beneficiary: ByteArray, vesting_end: Int) {
  withdraw(_redeemer: Data, _account: Credential, self: Transaction) {
    let after_vesting = interval.is_entirely_after(self.validity_range, vesting_end)
    let signed = list.has(self.extra_signatories, beneficiary)
    after_vesting && signed
  }
}

use aiken/collection/list
use cardano/address.{Credential}
use cardano/transaction.{Transaction}

validator conditional_staking(owner: ByteArray, guardian: ByteArray) {
  withdraw(emergency: Bool, _account: Credential, self: Transaction) {
    if emergency {
      list.has(self.extra_signatories, owner)
        && list.has(self.extra_signatories, guardian)
    } else {
      list.has(self.extra_signatories, owner)
    }
  }
}

use aiken/collection/list
use cardano/address.{Credential}
use cardano/transaction.{Transaction}

validator governance_withdraw(council: List<ByteArray>) {
  withdraw(_redeemer: Data, _account: Credential, self: Transaction) {
    let approvals = list.count(
      self.extra_signatories,
      fn(sig) { list.has(council, sig) },
    )
    approvals >= 2
  }
}

use aiken/collection/list
use aiken/interval
use cardano/address.{Credential}
use cardano/transaction.{Transaction}

validator override_staking(owner: ByteArray, override_key: ByteArray, deadline: Int) {
  withdraw(_redeemer: Data, _account: Credential, self: Transaction) {
    let after_deadline = interval.is_entirely_after(self.validity_range, deadline)
    if after_deadline {
      list.has(self.extra_signatories, override_key)
    } else {
      list.has(self.extra_signatories, owner)
    }
  }
}

use aiken/collection/list
use aiken/collection/pairs
use cardano/address.{Credential}
use cardano/transaction.{Transaction}

validator tiered_staking(owner: ByteArray, guardian: ByteArray, min_amount: Int) {
  withdraw(_redeemer: Data, account: Credential, self: Transaction) {
    let amount = when pairs.get_first(self.withdrawals, account) is {
      None -> 0
      Some(a) -> a
    }
    if amount >= min_amount {
      list.has(self.extra_signatories, owner)
        && list.has(self.extra_signatories, guardian)
    } else {
      list.has(self.extra_signatories, owner)
    }
  }
}

use aiken/collection/list
use cardano/address.{Credential}
use cardano/transaction.{Transaction}

pub type DaoRedeemer {
  approved: Bool,
}

validator dao_staking(council: List<ByteArray>) {
  withdraw(redeemer: DaoRedeemer, _account: Credential, self: Transaction) {
    let approvals = list.count(
      self.extra_signatories,
      fn(sig) { list.has(council, sig) },
    )
    redeemer.approved && approvals >= 2
  }
}
